#include <iostream>

int main() {
  int numbers[5] = {10, 20, 30, 40, 50};
  std::cout << "First element: " << numbers[0] << std::endl;
  std::cout << "Third element: " << numbers[2] << std::endl;
  return 0;
}
// Output:
// First element: 10
// Third element: 30

#include <iostream>

int main() {
  std::string names[3] = {"Alice", "Bob", "Charlie"};
  std::cout << "Second name: " << names[1] << std::endl;
  names[1] = "David";
  std::cout << "Updated second name: " << names[1] << std::endl;
  return 0;
}
// Output:
// Second name: Bob
// Updated second name: David

#include <iostream>

int main() {
  int matrix[2][3] = {{1, 2, 3}, {4, 5, 6}};
  std::cout << "Element at [1][2]: " << matrix[1][2] << std::endl;
  return 0;
}
// Output:
// Element at [1][2]: 6

#include <iostream>

void printArray(int arr[], int size) {
  for (int i = 0; i < size; i++) {
    std::cout << arr[i] << " ";
  }
  std::cout << std::endl;
}

int main() {
  int numbers[4] = {1, 2, 3, 4};
  printArray(numbers, 4);
  return 0;
}
// Output:
// 1 2 3 4

